#include <stdio.h>
#include <limits.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int a[N-1], b[N-2], c[N-3];
        for (int i = 0; i < N-1; i++) {
            scanf("%d", &a[i]);
        }
        for (int i = 0; i < N-2; i++) {
            scanf("%d", &b[i]);
        }
        for (int i = 0; i < N-3; i++) {
            scanf("%d", &c[i]);
        }
        long long dist[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                dist[i][j] = INT_MAX;
            }
        }
        for (int i = 0; i < N-1; i++) {
            dist[i][i+1] = a[i];
        }
        for (int i = 0; i < N-2; i++) {
            dist[i][i+2] = b[i];
        }
        for (int i = 0; i < N-3; i++) {
            dist[i][i+3] = c[i];
        }
        for (int k = 0; k < N; k++) {
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (dist[i][k] != INT_MAX && dist[k][j] != INT_MAX) {
                        dist[i][j] = (dist[i][j] == INT_MAX) ? dist[i][k] + dist[k][j] : (dist[i][j] < dist[i][k] + dist[k][j] ? dist[i][j] : dist[i][k] + dist[k][j]);
                    }
                }
            }
        }
        long long sum = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i+1; j < N; j++) {
                sum += dist[i][j];
            }
        }
        printf("%lld\n", sum);
    }
    return 0;
}

