                b[i] = sc.nextInt();
            }
            for (int i = 0; i < N-3; i++) {
                c[i] = sc.nextInt();
            }
            long[][] dist = new long[N][N];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
