                dist[i][i+3] = c[i];
            }
            for (int k = 0; k < N; k++) {
                for (int i = 0; i < N; i++) {
                    for (int j = 0; j < N; j++) {
                        if (dist[i][k] != Long.MAX_VALUE && dist[k][j] != Long.MAX_VALUE) {
                            dist[i][j] = (dist[i][j] == Long.MAX_VALUE) ? dist[i][k] + dist[k][j] : (dist[i][j] < dist[i][k] + dist[k][j] ? dist[i][j] : dist[i][k] + dist[k][j]);
