const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const a = readline().split(' ').map(Number);
    const b = readline().split(' ').map(Number);
    const c = readline().split(' ').map(Number);
    const dist = Array(N).fill().map(() => Array(N).fill(Infinity));
    for (let j = 0; j < N - 1; j++) {
        dist[j][j + 1] = a[j];
    }
    for (let j = 0; j < N - 2; j++) {
        dist[j][j + 2] = b[j];
    }
    for (let j = 0; j < N - 3; j++) {
        dist[j][j + 3] = c[j];
    }
    for (let k = 0; k < N; k++) {
        for (let j = 0; j < N; j++) {
            for (let l = 0; l < N; l++) {
                if (dist[j][k] !== Infinity && dist[k][l] !== Infinity) {
                    dist[j][l] = Math.min(dist[j][l], dist[j][k] + dist[k][l]);
                }
            }
        }
    }
    let sum = 0;
    for (let j = 0; j < N; j++) {
        for (let k = j + 1; k < N; k++) {
            sum += dist[j][k];
        }
    }
    console.log(sum);
}
